import{_ as t,o as a,c as i,ad as o}from"./chunks/framework.DdcUsuRQ.js";const m=JSON.parse('{"title":"Living color","description":"The v2 thesis. Treat a palette as a vector in OKLCH × N-roles space and animate between points while WCAG and role-schema constraints hold every frame.","frontmatter":{"title":"Living color","description":"The v2 thesis. Treat a palette as a vector in OKLCH × N-roles space and animate between points while WCAG and role-schema constraints hold every frame.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/v2-living-color"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/v2-living-color"}],["meta",{"property":"og:title","content":"Living color: iridis"}],["meta",{"property":"og:description","content":"The v2 thesis. Treat a palette as a vector in OKLCH × N-roles space and animate between points while WCAG and role-schema constraints hold every frame."}],["meta",{"name":"twitter:title","content":"Living color: iridis"}],["meta",{"name":"twitter:description","content":"The v2 thesis. Treat a palette as a vector in OKLCH × N-roles space and animate between points while WCAG and role-schema constraints hold every frame."}],["meta",{"name":"description","content":"The v2 thesis. Treat a palette as a vector in OKLCH × N-roles space and animate between points while WCAG and role-schema constraints hold every frame."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Living color\\",\\"item\\":\\"https://studnicky.github.io/iridis/v2-living-color\\"}]}"]]},"headers":[],"relativePath":"v2-living-color.md","filePath":"v2-living-color.md","lastUpdated":1779033869000}'),n={name:"v2-living-color.md"};function r(s,e,c,l,h,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="living-color" tabindex="-1">Living color <a class="header-anchor" href="#living-color" aria-label="Permalink to &quot;Living color&quot;">​</a></h1><p>A palette is a point in OKLCH × N-roles vector space. A static theme is a frozen point. A living palette is a path through that space, the way a chameleon or a cephalopod chromatophore does not pick a color but animates along a trajectory while preserving constraints (visibility, contrast, biological viability).</p><p>The v1 engine derives one point. The v2 thesis is that the same engine can animate between points and continue to enforce the same constraints (WCAG, role schemas, palette algebra) on every frame.</p><h2 id="vector-space-framing" tabindex="-1">Vector-space framing <a class="header-anchor" href="#vector-space-framing" aria-label="Permalink to &quot;Vector-space framing&quot;">​</a></h2><p>A palette of N roles is a vector of length 3·N:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>[L₁, C₁, h₁,  L₂, C₂, h₂,  ...,  Lₙ, Cₙ, hₙ]</span></span></code></pre></div><p>Each role contributes three coordinates in OKLCH. Two palettes are two points in that space. Animation is a parameterised curve</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>t ∈ [0, 1]  →  palette(t)</span></span></code></pre></div><p>that moves continuously from one point to another.</p><p>Easings shape the curve: linear, cubic-bezier, spring, or chromatic detour (a path that visits a third point so a warm-to-cool transition passes through green rather than brown). Hue wraparound has its own degree of freedom, clockwise, counter-clockwise, or shortest-arc.</p><p>The constraint stack runs per frame. A full pipeline derivation is well under a millisecond budget for a 12-role schema, which leaves room for <code>enforce:contrast</code> to keep WCAG ratios satisfied at every intermediate point on the curve.</p><h2 id="palette-algebra" tabindex="-1">Palette algebra <a class="header-anchor" href="#palette-algebra" aria-label="Permalink to &quot;Palette algebra&quot;">​</a></h2><p>Vector framing makes a small algebra fall out for free.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Meaning</th></tr></thead><tbody><tr><td><code>lerp(a, b, 0.3)</code></td><td>thirty percent of the way from <code>a</code> toward <code>b</code></td></tr><tr><td><code>a − b</code></td><td>per-role OKLCH delta vector</td></tr><tr><td><code>nearest(a, corpus)</code></td><td>closest preset to a custom palette under a perceptual metric</td></tr><tr><td><code>drift(current, derived) &gt; θ</code></td><td>&quot;the user adjusted accent past tolerance, re-derive?&quot;</td></tr><tr><td><code>perpendicular(a, axis)</code></td><td>move orthogonally on the chroma plane while holding L and h</td></tr></tbody></table><p>These are not separate features. They are consequences of treating the palette as a vector and the pipeline as a function from vector to vector.</p><h2 id="reactive-bindings" tabindex="-1">Reactive bindings <a class="header-anchor" href="#reactive-bindings" aria-label="Permalink to &quot;Reactive bindings&quot;">​</a></h2><p>Once the engine produces palette(t), the parameter t can come from anywhere, a clock, an audio FFT bin, scroll position, focus state, ambient light, weather data, a finite-state machine over user mood. The engine does not need to know the source. The binding layer reads a signal, maps it to t, and asks the engine for the palette at that point.</p><p>This is the second half of the thesis. A static palette answers &quot;what colors&quot;. A living palette answers &quot;what colors right now, given what is happening&quot;.</p><h2 id="why-this-matters" tabindex="-1">Why this matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why this matters&quot;">​</a></h2><p>A theme that responds to time, content, and context is closer to the way colour works in nature than the catalogues of frozen tokens that ship with most design systems. The wedge is the combination: vector palettes plus role schemas plus contrast enforcement plus animation plus reactive signals, in one engine, with the constraints holding on every frame.</p>',20)])])}const v=t(n,[["render",r]]);export{m as __pageData,v as default};
